  },
  "sessionLineMapLength": 1,
  "sessionContent": "User: hello",
  "compiledSourceCount": 1,
  "updatedFiles": [
    ".openclaw-wiki/cache/agent-digest.json",
    ".openclaw-wiki/cache/claims.jsonl",
    "concepts/index.md",
    "entities/index.md",
    "index.md",
    "reports/claim-health.md",
    "reports/contradictions.md",
    "reports/index.md",
